introduction--docs.content:
import { Meta } from "@storybook/addon-docs/blocks";

<Meta title="Introduction" />

<div className="sb-container">
  <div className="sb-header">
    <div className="sb-logo">R</div>
    <div className="sb-header-text">
      <h1>ReactUI Template</h1>
      <p className="sb-subtitle">A premium, highly-interactive React UI Library built with TypeScript, Vite, and Tailwind CSS.</p>
    </div>
  </div>

  {/* ZIP Download Section */}
  <div className="download-container">
    <div className="download-card">
      <div className="download-details">
        <h4>Get Codebase ZIP Archive</h4>
        <p>Download the complete project workspace directly. Use this to bypass manual cloning and bootstrap your development workflow instantly.</p>
      </div>
      <a 
        href="https://github.com/HemalPragetx17/react-template/archive/refs/heads/master.zip" 
        className="download-btn" 
        target="_blank"
        rel="noopener noreferrer"
      >
        <svg stroke="currentColor" fill="none" strokeWidth="2.5" viewBox="0 0 24 24" strokeLinecap="round" strokeLinejoin="round" height="16" width="16" xmlns="http://www.w3.org/2000/svg">
          <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
          <polyline points="7 10 12 15 17 10"></polyline>
          <line x1="12" y1="15" x2="12" y2="3"></line>
        </svg>
        Download ZIP File
      </a>
    </div>
  </div>

  {/* Main Setup Instructions */}
  <div className="setup-section">
    <h2>Project Setup & Installation</h2>
    <p>Follow these standard terminal steps to get your local environment configured and running:</p>

    <div className="step-list">
      <div className="step-item">
        <div className="step-badge">1</div>
        <div className="step-content">
          <h4>Clone the Codebase</h4>
          <p>Clone the repository and enter the workspace folder:</p>
          <pre><code>git clone https://github.com/HemalPragetx17/react-template.git{"\n"}cd react-template</code></pre>
        </div>
      </div>

      <div className="step-item">
        <div className="step-badge">2</div>
        <div className="step-content">
          <h4>Install Node Modules</h4>
          <p>Install the required packages using NPM:</p>
          <pre><code>npm install</code></pre>
        </div>
      </div>

      <div className="step-item">
        <div className="step-badge">3</div>
        <div className="step-content">
          <h4>Launch Application Development</h4>
          <p>Run the Vite local dev server (available at <code>http://localhost:3000</code>):</p>
          <pre><code>npm run dev</code></pre>
        </div>
      </div>

    </div>
  </div>

  {/* Architecture Details */}
  <div className="architecture-grid">
    <div className="arch-card">
      <h4>Vite Bundler</h4>
      <p>Configured for speed and tree-shaking support, yielding highly-optimized CSS/JS assets on production builds.</p>
    </div>
    <div className="arch-card">
      <h4>Tailwind CSS</h4>
      <p>Theme settings mapped directly to CSS custom properties (variables) in index.css to support light/dark systems smoothly.</p>
    </div>
    <div className="arch-card">
      <h4>Framer Motion</h4>
      <p>Smooth page animations, spring transitions, and interactive micro-effects built straight into core buttons and overlays.</p>
    </div>
  </div>
</div>

